import{_ as t,C as n,o,c as l,j as a,a as i,E as h,a3 as d}from"./chunks/framework.CMLpj6w5.js";const y=JSON.parse('{"title":"Update Check","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/update-check.md","filePath":"advanced/update-check.md"}'),r={name:"advanced/update-check.md"},c={id:"update-check",tabindex:"-1"};function p(k,e,u,g,m,f){const s=n("VersionBadge");return o(),l("div",null,[a("h1",c,[e[0]||(e[0]=i("Update Check ",-1)),h(s,{v:"0.9.0"}),e[1]||(e[1]=i()),e[2]||(e[2]=a("a",{class:"header-anchor",href:"#update-check","aria-label":'Permalink to "Update Check <VersionBadge v="0.9.0" />"'},"​",-1))]),e[3]||(e[3]=d('<p>When a newer version of amoxide lands on crates.io, <code>am ls</code> tells you the next time you list. The nudge goes to stderr, the check runs in the background, and you can turn it off.</p><h2 id="what-you-see" tabindex="-1">What you see <a class="header-anchor" href="#what-you-see" aria-label="Permalink to &quot;What you see&quot;">​</a></h2><p>If you&#39;re behind, the listing commands (<code>am ls</code>, <code>am la</code>, <code>am profile list</code>) print one line on stderr after the listing:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>am: 💡 a new version is available: v0.9.0 -&gt; visit https://github.com/sassman/amoxide-rs/releases</span></span></code></pre></div><p>If you&#39;re up to date, you see nothing.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><ul><li>First time you run a listing command, amoxide spawns a detached child that hits crates.io. The listing prints right away — you don&#39;t wait for the network.</li><li>The result lands in <code>~/.cache/amoxide/update-check.toml</code>.</li><li>Next time you list, amoxide reads that file. If it&#39;s older than 24 hours, a fresh background check kicks off and the previous result (if there is one) is shown in the meantime.</li><li>Network errors are silent. Offline, DNS broken, crates.io down — the listing still works, the nudge just doesn&#39;t appear.</li></ul><p>The nudge is on stderr, so pipes are unaffected:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-alias</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # nudge stays out of the pipe</span></span></code></pre></div><h2 id="disabling-the-check" tabindex="-1">Disabling the check <a class="header-anchor" href="#disabling-the-check" aria-label="Permalink to &quot;Disabling the check&quot;">​</a></h2><p>Two ways: a config flag (persistent) or an env var (one-shot, for CI).</p><h3 id="config-config-amoxide-config-toml" tabindex="-1">Config: <code>~/.config/amoxide/config.toml</code> <a class="header-anchor" href="#config-config-amoxide-config-toml" aria-label="Permalink to &quot;Config: `~/.config/amoxide/config.toml`&quot;">​</a></h3><div class="language-toml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">update</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">check = </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span></code></pre></div><p>With <code>check = false</code>, no cache read, no spawn, no network call. The cache file is never created.</p><h3 id="environment-am-no-update-check" tabindex="-1">Environment: <code>AM_NO_UPDATE_CHECK</code> <a class="header-anchor" href="#environment-am-no-update-check" aria-label="Permalink to &quot;Environment: `AM_NO_UPDATE_CHECK`&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AM_NO_UPDATE_CHECK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span></span></code></pre></div><p>Any non-empty value skips the check for that one call. Handy in CI where you don&#39;t want network traffic and don&#39;t want to maintain a config.</p><h2 id="privacy" tabindex="-1">Privacy <a class="header-anchor" href="#privacy" aria-label="Permalink to &quot;Privacy&quot;">​</a></h2><p>One HTTPS GET to <code>https://crates.io/api/v1/crates/amoxide</code>. That&#39;s the whole call — crate name plus ureq&#39;s default User-Agent. Nothing identifies you, nothing tracks usage.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/_preview/125/advanced/config-files">Config Files</a> — full TOML reference</li></ul>',21))])}const v=t(r,[["render",p]]);export{y as __pageData,v as default};
